import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";

import Gallery from "./components/Gallery";
import Cart from "./components/Cart";
import Payment from "./components/Payment";
import Contact from "./components/Contact";
import Confirmation from "./components/Confirmation";
import Mission from "./components/Mission";
import "./App.css"; // ✅ style navigation + responsive

function App() {
  const [cart, setCart] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  return (
    <Router>
      <div>
        {/* Navigation principale */}
        <nav className="navbar">
          <div className="nav-logo">🎨 Artistes de Grenoble</div>

          {/* Bouton menu burger pour mobile */}
          <div className="burger" onClick={toggleMenu}>
            ☰
          </div>

          {/* Liens de navigation */}
          <div className={`nav-links ${menuOpen ? "open" : ""}`}>
            <Link to="/" onClick={() => setMenuOpen(false)}>Accueil</Link>
            <Link to="/gallery" onClick={() => setMenuOpen(false)}>Galerie</Link>
            <Link to="/cart" onClick={() => setMenuOpen(false)}>
              Panier ({cart.length})
            </Link>
            <Link to="/contact" onClick={() => setMenuOpen(false)}>Contact</Link>
            <Link to="/mission" onClick={() => setMenuOpen(false)}>Notre Mission</Link>
          </div>
        </nav>

        {/* Contenu des pages */}
        <div className="page-content">
          <Routes>
            <Route
              path="/"
              element={<h1 style={{ textAlign: "center" }}>Bienvenue sur le site des artistes 🎨</h1>}
            />
            <Route path="/gallery" element={<Gallery cart={cart} setCart={setCart} />} />
            <Route path="/cart" element={<Cart cart={cart} setCart={setCart} />} />
            <Route path="/payment" element={<Payment cart={cart} setCart={setCart} />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/confirmation" element={<Confirmation />} />
            <Route path="/mission" element={<Mission />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
